import './index.css';
import './media.css';

import React from 'react'
import { BrowserRouter, Routes, Route } from "react-router-dom";
import ReactDOM from 'react-dom/client'

import Homepage from './components/Homepage/Homepage.jsx'
import Contatos from './components/ContactPage/Contatos.jsx';
import Header from './components/Header/Header.jsx';
import Footer from './components/Footer/Footer.jsx';

const root = ReactDOM.createRoot(document.getElementById("root"))
const repositorio = "https://gldhperes.github.io/peres-seguranca-react/"
root.render(

    <BrowserRouter  >

        <div style={{
            width: '100%',
            display: 'flex',
            flexFlow: 'column'
        }}>

            <Header />

            <Routes>

                <Route path={repositorio} exact element={<Homepage />} />
                <Route path={repositorio + "contatos"} exact element={<Contatos />} />

            </Routes>
            <Footer />
        </div>

    </BrowserRouter>


);
